// modules/auth/routes/password-reset-request.ts
import { Request, Response } from 'bun';
import { sendPasswordResetEmail } from '../lib/email';
import { Result, ok, err } from '../../../lib/result';

export async function passwordResetRequest(req: Request): Promise<Response> {
  const email = req.parsedUrl.searchParams.get('email');

  if (!email) {
    return new Response(JSON.stringify({ error: 'Email parameter is required' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  try {
    const result = await sendPasswordResetEmail(email);
    if (result.isOk()) {
      return new Response(JSON.stringify({ message: 'Password reset email sent successfully' }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' },
      });
    } else {
      return new Response(JSON.stringify({ error: result.error.message }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' },
      });
    }
  } catch (error) {
    console.error('Error sending password reset email:', error);
    return new Response(JSON.stringify({ error: 'Internal server error' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }
}

